// Calcula métricas de la última semana (Sheets) + mejores publicaciones (Meta)
const leads = $('Leer Leads').all().map(i => i.json);
const agenda = $('Leer Agenda').all().map(i => i.json);
const hoy = new Date();
const hace7 = new Date(hoy.getTime() - 7*24*60*60*1000);
const dentroSemana = (f) => { const d = new Date(f); return d >= hace7 && d <= hoy; };

const leadsSemana = leads.filter(l => dentroSemana(l.fecha));
const porCanal = {};
leadsSemana.forEach(l => { const c = l.canal || 'otro'; porCanal[c] = (porCanal[c]||0)+1; });
const cerrados = leadsSemana.filter(l => (l.estado||'').toLowerCase() === 'cerrado').length;
const llamadas = agenda.filter(a => dentroSemana(a.fecha_hora || a.fecha)).length;
const total = leadsSemana.length;
const conv = total ? Math.round((cerrados/total)*100) : 0;

// Mejores publicaciones de la semana según Meta (si está configurado)
let topPosts = [];
try {
  const media = $('Traer Insights (Meta)').first().json?.data || [];
  topPosts = media
    .filter(m => dentroSemana(m.timestamp))
    .map(m => {
      const ins = (m.insights?.data || []).reduce((a,x)=>{a[x.name]=x.values?.[0]?.value; return a;}, {});
      return { caption: (m.caption||'').slice(0,60), link: m.permalink, likes: m.like_count||0, comentarios: m.comments_count||0, alcance: ins.reach||0, interacciones: ins.total_interactions||0 };
    })
    .sort((a,b) => (b.interacciones||0) - (a.interacciones||0))
    .slice(0, 3);
} catch (e) { topPosts = []; }

return [{ json: {
  total_contactos: total,
  por_canal: porCanal,
  leads_cerrados: cerrados,
  conversion_pct: conv,
  llamadas_agendadas: llamadas,
  mejores_publicaciones: topPosts,
  detalle: leadsSemana.map(l => ({ canal: l.canal, interes: l.interes, estado: l.estado }))
}}];

const m = $('Calcular métricas').item.json;
const texto = $json.message?.content || $json.text || '';
const canales = Object.entries(m.por_canal).map(([k,v]) => `  • ${k}: ${v}`).join('
') || '  • (sin contactos)';
const body = `📊 *Reporte semanal RedLabs*

👥 Contactaron: ${m.total_contactos}
${canales}
✅ Cerrados: ${m.leads_cerrados} (conversión ${m.conversion_pct}%)
📞 Llamadas agendadas: ${m.llamadas_agendadas}

${texto}`;
return [{ json: { body } }];
